def token_case(s, exceptions=['URL', 'ID']):
    tokens = s.strip().split('_')
    camel_case_tokens = []

    for i, token in enumerate(tokens):
        if token.upper() in exceptions:
            camel_case_tokens.append(token)
        elif i == 0:
            camel_case_tokens.append(token.lower())
        else:
            camel_case_tokens.append(token.capitalize())

    return ''.join(camel_case_tokens)

# Edge case: leading and trailing underscores
print(token_case("__example_string__"))  # Expected output: "exampleString"
